def solve():
    import sys
    from collections import deque

    data = sys.stdin.read().split("\n")
    r, c = map(int, data[0].split())
    grid = [data[1 + i] for i in range(r)]

    visited = [[False] * c for _ in range(r)]
    count = 0
    for i in range(r):
        for j in range(c):
            if grid[i][j] == "1" and not visited[i][j]:
                count += 1  # 새로운 섬 발견
                q = deque([(i, j)])
                visited[i][j] = True
                while q:
                    y, x = q.popleft()
                    for dy, dx in ((1, 0), (-1, 0), (0, 1), (0, -1)):
                        ny, nx = y + dy, x + dx
                        if 0 <= ny < r and 0 <= nx < c and not visited[ny][nx] and grid[ny][nx] == "1":
                            visited[ny][nx] = True
                            q.append((ny, nx))

    print(count)

solve()
